import { useState, useCallback } from 'react'
import { TileLayout } from '../components/TiledTerminalView'

type ViewMode = 'tabs' | 'tiled'

interface UseViewStateReturn {
  viewMode: ViewMode
  tileLayout: TileLayout[]
  lastFocusedTabId: string | null
  sidebarWidth: number
  sidebarCollapsed: boolean
  setViewMode: (mode: ViewMode) => void
  setTileLayout: (layout: TileLayout[]) => void
  setLastFocusedTabId: (id: string | null) => void
  setSidebarWidth: (width: number) => void
  setSidebarCollapsed: (collapsed: boolean) => void
  toggleViewMode: () => void
}

export function useViewState(): UseViewStateReturn {
  const [viewMode, setViewModeState] = useState<ViewMode>('tabs')
  const [tileLayout, setTileLayout] = useState<TileLayout[]>([])
  const [lastFocusedTabId, setLastFocusedTabId] = useState<string | null>(null)
  const [sidebarWidth, setSidebarWidth] = useState(280)
  const [sidebarCollapsed, setSidebarCollapsed] = useState(false)

  const setViewMode = useCallback((mode: ViewMode) => {
    setViewModeState(mode)
    // Trigger resize events to force terminals to refit after view mode change
    setTimeout(() => window.dispatchEvent(new Event('resize')), 50)
    setTimeout(() => window.dispatchEvent(new Event('resize')), 150)
    setTimeout(() => window.dispatchEvent(new Event('resize')), 300)
  }, [])

  const toggleViewMode = useCallback(() => {
    setViewMode(viewMode === 'tabs' ? 'tiled' : 'tabs')
  }, [viewMode, setViewMode])

  return {
    viewMode,
    tileLayout,
    lastFocusedTabId,
    sidebarWidth,
    sidebarCollapsed,
    setViewMode,
    setTileLayout,
    setLastFocusedTabId,
    setSidebarWidth,
    setSidebarCollapsed,
    toggleViewMode
  }
}

/**
 * Settings Routes
 *
 * HTTP endpoints for application settings, voice configuration, and CLI status.
 */

import { Router, Request, Response } from 'express'
import {
  ApiResponse,
  Settings,
  VoiceSettings
} from '../types'
import { getServices } from '../app'

const router = Router()

// =============================================================================
// Helper Functions
// =============================================================================

function sendResponse<T>(res: Response, statusCode: number, data: ApiResponse<T>): void {
  res.status(statusCode).json(data)
}

function sendError(res: Response, statusCode: number, error: string): void {
  sendResponse(res, statusCode, {
    success: false,
    error,
    timestamp: Date.now()
  })
}

// =============================================================================
// Application Settings Routes
// =============================================================================

/**
 * GET /api/settings
 * Get application settings
 *
 * Returns: Settings
 */
router.get('/', async (_req: Request, res: Response) => {
  try {
    const services = getServices()

    if (!services.getSettings) {
      return sendError(res, 503, 'Settings service not available')
    }

    const settings: Settings = await services.getSettings()

    sendResponse<Settings>(res, 200, {
      success: true,
      data: settings,
      timestamp: Date.now()
    })
  } catch (error: any) {
    console.error('[Settings Route] Get error:', error)
    sendError(res, 500, error.message || 'Failed to get settings')
  }
})

/**
 * PUT /api/settings
 * Save application settings
 *
 * Body: Settings
 */
router.put('/', async (req: Request, res: Response) => {
  try {
    const services = getServices()

    if (!services.saveSettings) {
      return sendError(res, 503, 'Settings service not available')
    }

    const settings: Settings = req.body

    // Basic validation
    if (!settings || typeof settings !== 'object') {
      return sendError(res, 400, 'Invalid settings data')
    }

    await services.saveSettings(settings)

    sendResponse(res, 200, {
      success: true,
      timestamp: Date.now()
    })
  } catch (error: any) {
    console.error('[Settings Route] Save error:', error)
    sendError(res, 500, error.message || 'Failed to save settings')
  }
})

/**
 * PATCH /api/settings
 * Partially update application settings
 *
 * Body: Partial<Settings>
 */
router.patch('/', async (req: Request, res: Response) => {
  try {
    const services = getServices()

    if (!services.getSettings || !services.saveSettings) {
      return sendError(res, 503, 'Settings service not available')
    }

    const updates: Partial<Settings> = req.body

    // Get current settings and merge
    const currentSettings = await services.getSettings()
    const newSettings = { ...currentSettings, ...updates }

    await services.saveSettings(newSettings)

    sendResponse<Settings>(res, 200, {
      success: true,
      data: newSettings,
      timestamp: Date.now()
    })
  } catch (error: any) {
    sendError(res, 500, error.message || 'Failed to update settings')
  }
})

// =============================================================================
// Voice Settings Routes
// =============================================================================

/**
 * GET /api/settings/voice
 * Get voice settings
 *
 * Returns: VoiceSettings
 */
router.get('/voice', async (_req: Request, res: Response) => {
  try {
    const services = getServices()

    if (!services.voiceGetSettings) {
      return sendError(res, 503, 'Voice service not available')
    }

    const settings: VoiceSettings = await services.voiceGetSettings()

    sendResponse<VoiceSettings>(res, 200, {
      success: true,
      data: settings,
      timestamp: Date.now()
    })
  } catch (error: any) {
    sendError(res, 500, error.message || 'Failed to get voice settings')
  }
})

/**
 * POST /api/settings/voice/speak
 * Speak text using TTS
 *
 * Body: { text: string }
 */
router.post('/voice/speak', async (req: Request, res: Response) => {
  try {
    const services = getServices()

    if (!services.voiceSpeak) {
      return sendError(res, 503, 'Voice service not available')
    }

    const { text } = req.body

    if (!text || typeof text !== 'string') {
      return sendError(res, 400, 'text is required and must be a string')
    }

    // Limit text length to prevent abuse
    if (text.length > 5000) {
      return sendError(res, 400, 'text must be 5000 characters or less')
    }

    const result = await services.voiceSpeak(text)

    sendResponse(res, result.success ? 200 : 500, {
      success: result.success,
      data: result.audioData ? { audioData: result.audioData } : undefined,
      error: result.error,
      timestamp: Date.now()
    })
  } catch (error: any) {
    sendError(res, 500, error.message || 'Failed to speak text')
  }
})

/**
 * POST /api/settings/voice/stop
 * Stop TTS playback
 */
router.post('/voice/stop', async (_req: Request, res: Response) => {
  try {
    const services = getServices()

    if (!services.voiceStopSpeaking) {
      return sendError(res, 503, 'Voice service not available')
    }

    const result = await services.voiceStopSpeaking()

    sendResponse(res, result.success ? 200 : 500, {
      success: result.success,
      timestamp: Date.now()
    })
  } catch (error: any) {
    sendError(res, 500, error.message || 'Failed to stop speaking')
  }
})

// =============================================================================
// CLI Status Routes
// =============================================================================

/**
 * GET /api/settings/cli/status
 * Get installation status of all CLI tools
 *
 * Returns: { claude, gemini, codex, opencode, aider }
 */
router.get('/cli/status', async (_req: Request, res: Response) => {
  try {
    const services = getServices()

    const status: Record<string, any> = {}

    // Check each CLI tool in parallel
    const checks = await Promise.allSettled([
      services.claudeCheck?.() ?? Promise.resolve({ installed: false }),
      services.geminiCheck?.() ?? Promise.resolve({ installed: false }),
      services.codexCheck?.() ?? Promise.resolve({ installed: false }),
      services.opencodeCheck?.() ?? Promise.resolve({ installed: false }),
      services.aiderCheck?.() ?? Promise.resolve({ installed: false })
    ])

    const cliNames = ['claude', 'gemini', 'codex', 'opencode', 'aider']

    checks.forEach((result, index) => {
      if (result.status === 'fulfilled') {
        status[cliNames[index]] = result.value
      } else {
        status[cliNames[index]] = { installed: false, error: result.reason?.message }
      }
    })

    sendResponse(res, 200, {
      success: true,
      data: status,
      timestamp: Date.now()
    })
  } catch (error: any) {
    sendError(res, 500, error.message || 'Failed to check CLI status')
  }
})

/**
 * GET /api/settings/cli/:tool
 * Get installation status of a specific CLI tool
 *
 * Params: tool - one of: claude, gemini, codex, opencode, aider
 */
router.get('/cli/:tool', async (req: Request, res: Response) => {
  try {
    const services = getServices()
    const { tool } = req.params

    const checkFunctions: Record<string, (() => Promise<any>) | undefined> = {
      claude: services.claudeCheck,
      gemini: services.geminiCheck,
      codex: services.codexCheck,
      opencode: services.opencodeCheck,
      aider: services.aiderCheck
    }

    const checkFn = checkFunctions[tool]
    if (!checkFn) {
      return sendError(res, 400, `Unknown tool: ${tool}. Valid tools: ${Object.keys(checkFunctions).join(', ')}`)
    }

    const result = await checkFn()

    sendResponse(res, 200, {
      success: true,
      data: result,
      timestamp: Date.now()
    })
  } catch (error: any) {
    sendError(res, 500, error.message || 'Failed to check CLI status')
  }
})

export default router

import { app } from 'electron'
import { existsSync, mkdirSync, readFileSync, writeFileSync, renameSync, statSync } from 'fs'
import { join } from 'path'
import { syncMetaProjects } from './meta-project-sync'

export interface ProjectCategory {
  id: string
  name: string
  collapsed: boolean
  order: number
}

export interface Project {
  path: string
  name: string
  executable?: string
  apiPort?: number  // Port for HTTP API to send prompts to terminal
  apiAutoStart?: boolean  // Whether to auto-start API when session opens (default: false)
  apiSessionMode?: 'existing' | 'new-keep' | 'new-close'  // How API requests handle sessions
  apiModel?: 'default' | 'opus' | 'sonnet' | 'haiku'  // Model for API-triggered sessions
  autoAcceptTools?: string[]  // Per-project tool patterns to auto-accept
  permissionMode?: string     // Per-project permission mode
  color?: string              // Project color for visual identification
  ttsVoice?: string           // Per-project TTS voice (overrides global)
  ttsEngine?: 'piper' | 'xtts'  // Per-project TTS engine
  backend?: 'default' | 'claude' | 'gemini' | 'codex' | 'opencode' | 'aider' // Per-project backend (overrides global)
  categoryId?: string         // Category this project belongs to
  order?: number              // Order within category or uncategorized list
}

export interface OpenTab {
  id: string
  projectPath: string
  sessionId?: string
  title: string
  ptyId?: string
  backend?: 'default' | 'claude' | 'gemini' | 'codex' | 'opencode' | 'aider'
}

export interface TileLayout {
  id: string
  tabIds: string[]
  activeTabId: string
  x: number
  y: number
  width: number
  height: number
}

export interface Workspace {
  projects: Project[]
  openTabs: OpenTab[]
  activeTabId: string | null
  viewMode?: 'tabs' | 'tiled'
  tileLayout?: TileLayout[]
  categories?: ProjectCategory[]
}

export interface WindowBounds {
  x: number
  y: number
  width: number
  height: number
}

export interface ThemeCustomization {
  accentColor: string | null
  backgroundColor: string | null
  textColor: string | null
  terminalColors: {
    black?: string
    red?: string
    green?: string
    yellow?: string
    blue?: string
    magenta?: string
    cyan?: string
    white?: string
  } | null
}

export interface Settings {
  defaultProjectDir: string
  theme: string
  themeCustomization?: ThemeCustomization | null
  voiceOutputEnabled?: boolean
  voiceVolume?: number
  voiceSpeed?: number
  voiceSkipOnNew?: boolean
  voiceSilenceThreshold?: number
  autoAcceptTools?: string[]
  permissionMode?: string
  backend?: 'default' | 'claude' | 'gemini' | 'codex' | 'opencode' | 'aider'
}


interface StoredData {
  workspace: Workspace
  windowBounds?: WindowBounds
  settings?: Settings
}

export class SessionStore {
  private configPath: string
  private backupPath: string
  private data: StoredData

  constructor() {
    const configDir = join(app.getPath('userData'), 'config')
    if (!existsSync(configDir)) {
      mkdirSync(configDir, { recursive: true })
    }
    this.configPath = join(configDir, 'workspace.json')
    this.backupPath = join(configDir, 'workspace.json.backup')
    this.data = this.load()
  }

  private loadFile(path: string): StoredData | null {
    try {
      if (!existsSync(path)) return null
      const stat = statSync(path)
      if (stat.size === 0) return null
      const content = readFileSync(path, 'utf-8')
      const data = JSON.parse(content)
      if (!data?.workspace) return null
      return data
    } catch (e) {
      console.error(`[SessionStore] Failed to load ${path}:`, e)
      return null
    }
  }

  private load(): StoredData {
    // Try main file first
    const main = this.loadFile(this.configPath)
    if (main && (main.workspace.projects?.length || 0) > 0) {
      return main
    }

    // Main file is empty/corrupt/missing — try backup
    const backup = this.loadFile(this.backupPath)
    if (backup && (backup.workspace.projects?.length || 0) > 0) {
      console.log('[SessionStore] Main config empty/corrupt, restored from backup (' +
        backup.workspace.projects.length + ' projects)')
      // Restore backup as main file immediately
      try {
        writeFileSync(this.configPath, JSON.stringify(backup, null, 2))
      } catch (e) {
        console.error('[SessionStore] Failed to restore backup to main:', e)
      }
      return backup
    }

    // If main loaded but had 0 projects (valid empty state), use it
    if (main) return main

    return {
      workspace: {
        projects: [],
        openTabs: [],
        activeTabId: null
      }
    }
  }

  private save(): void {
    try {
      const json = JSON.stringify(this.data, null, 2)

      // Validate we can parse what we're about to write
      JSON.parse(json)

      // Back up existing file before overwriting (if it has content)
      if (existsSync(this.configPath)) {
        try {
          const stat = statSync(this.configPath)
          if (stat.size > 0) {
            // Only update backup if existing file is valid and has projects
            const existing = this.loadFile(this.configPath)
            if (existing && (existing.workspace.projects?.length || 0) > 0) {
              writeFileSync(this.backupPath, readFileSync(this.configPath))
            }
          }
        } catch (e) {
          console.error('[SessionStore] Failed to update backup:', e)
        }
      }

      // Atomic write: write to temp file, then rename
      const tmpPath = this.configPath + '.tmp'
      writeFileSync(tmpPath, json)

      // Verify the temp file was written completely
      const written = readFileSync(tmpPath, 'utf-8')
      JSON.parse(written) // throws if truncated/corrupt

      renameSync(tmpPath, this.configPath)
    } catch (e) {
      console.error('[SessionStore] Failed to save workspace:', e)
    }
  }

  getWorkspace(): Workspace {
    return this.data.workspace
  }

  // Reload workspace from disk (useful when file was modified externally)
  reloadFromDisk(): void {
    console.log('[SessionStore] Reloading workspace from disk')
    this.data = this.load()
    console.log('[SessionStore] Reloaded, projects:', this.data.workspace?.projects?.length || 0)
  }

  saveWorkspace(workspace: Workspace): void {
    // Protect against overwriting populated workspace with empty one
    const incomingProjects = workspace?.projects?.length || 0
    const currentProjects = this.data.workspace?.projects?.length || 0
    if (incomingProjects === 0 && currentProjects > 0) {
      console.log('[SessionStore] Rejected empty workspace save - current has', currentProjects, 'projects')
      return
    }
    this.data.workspace = workspace
    this.save()
    syncMetaProjects(workspace)
  }

  getWindowBounds(): WindowBounds | undefined {
    return this.data.windowBounds
  }

  saveWindowBounds(bounds: WindowBounds): void {
    this.data.windowBounds = bounds
    this.save()
  }

  getSettings(): Settings {
    return this.data.settings ?? { defaultProjectDir: '', theme: 'default', backend: 'default' }
  }

  saveSettings(settings: Settings): void {
    this.data.settings = settings
    this.save()
  }
}

