import React from 'react'
import { Project } from '../../stores/workspace.js'
import { ProjectIcon } from '../ProjectIcon.js'
import { ClaudeSession, DropTarget } from './types.js'
import { formatDate } from './utils.js'

interface ProjectItemProps {
  project: Project
  isExpanded: boolean
  isFocused: boolean
  hasOpenTab: boolean
  isDragging: boolean
  isEditing: boolean
  editingName: string
  sessions: ClaudeSession[]
  taskCounts?: { open: number; inProgress: number }
  dropTarget: DropTarget | null
  editInputRef: React.RefObject<HTMLInputElement | null>
  onToggleExpand: (e: React.MouseEvent) => void
  onOpenSession: (sessionId?: string, slug?: string, isNewSession?: boolean) => void
  onRunExecutable: () => void
  onCloseProjectTabs: () => void
  onContextMenu: (e: React.MouseEvent) => void
  onDragStart: (e: React.DragEvent) => void
  onDragEnd: () => void
  onDragOver: (e: React.DragEvent) => void
  onDrop: (e: React.DragEvent) => void
  onStartRename: (e: React.MouseEvent) => void
  onEditingChange: (name: string) => void
  onRenameSubmit: () => void
  onRenameKeyDown: (e: React.KeyboardEvent) => void
}

export const ProjectItem = React.memo(function ProjectItem({
  project,
  isExpanded,
  isFocused,
  hasOpenTab,
  isDragging,
  isEditing,
  editingName,
  sessions,
  taskCounts,
  dropTarget,
  editInputRef,
  onToggleExpand,
  onOpenSession,
  onRunExecutable,
  onCloseProjectTabs,
  onContextMenu,
  onDragStart,
  onDragEnd,
  onDragOver,
  onDrop,
  onStartRename,
  onEditingChange,
  onRenameSubmit,
  onRenameKeyDown,
}: ProjectItemProps) {
  const showDropBefore = dropTarget?.type === 'project' && dropTarget.id === project.path && dropTarget.position === 'before'
  const showDropAfter = dropTarget?.type === 'project' && dropTarget.id === project.path && dropTarget.position === 'after'

  return (
    <div>
      {showDropBefore && <div className="drop-indicator" />}

      <div
        className={`project-item ${isExpanded ? 'expanded' : ''} ${hasOpenTab ? 'has-open-tab' : ''} ${project.executable ? 'has-executable' : ''} ${project.color ? 'has-color' : ''} ${isFocused ? 'focused' : ''} ${isDragging ? 'dragging' : ''}`}
        style={project.color ? { backgroundColor: `${project.color}20` } : undefined}
        draggable={!isEditing}
        onDragStart={onDragStart}
        onDragEnd={onDragEnd}
        onDragOver={onDragOver}
        onDrop={onDrop}
        onClick={() => onOpenSession()}
        onContextMenu={onContextMenu}
      >
        <button
          className="expand-arrow"
          onClick={onToggleExpand}
          title="Show all sessions"
          aria-expanded={isExpanded}
          aria-label={`${isExpanded ? 'Collapse' : 'Expand'} sessions for ${project.name}`}
        >
          {isExpanded ? '▼' : '▶'}
        </button>
        <ProjectIcon projectName={project.name} size={28} />
        <div style={{ flex: 1, minWidth: 0 }}>
          {isEditing ? (
            <input
              ref={editInputRef}
              type="text"
              className="project-name-input"
              value={editingName}
              onChange={(e) => onEditingChange(e.target.value)}
              onKeyDown={onRenameKeyDown}
              onBlur={onRenameSubmit}
              onClick={(e) => e.stopPropagation()}
            />
          ) : (
            <div
              className="project-name"
              title={project.name}
              onDoubleClick={onStartRename}
            >
              {project.name}
            </div>
          )}
          {taskCounts ? (
            <div className="project-tasks" title={project.path}>
              {taskCounts.open + taskCounts.inProgress > 0 ? (
                <>
                  <span className="task-count">{taskCounts.open + taskCounts.inProgress} tasks</span>
                  {taskCounts.inProgress > 0 && (
                    <span className="task-in-progress">({taskCounts.inProgress} active)</span>
                  )}
                </>
              ) : (
                <span className="task-count task-done">No open tasks</span>
              )}
            </div>
          ) : (
            <div className="project-path" title={project.path}>{project.path}</div>
          )}
        </div>
        {project.executable && (
          <button
            className="start-btn"
            onClick={(e) => {
              e.stopPropagation()
              onRunExecutable()
            }}
            title={`Run: ${project.executable}`}
          >
            ▶
          </button>
        )}
        {hasOpenTab && (
          <button
            className="close-project-btn"
            onClick={(e) => {
              e.stopPropagation()
              onCloseProjectTabs()
            }}
            title="Close all terminals for this project"
          >
            ×
          </button>
        )}
      </div>

import { useCallback } from 'react'
import { Project } from '../../stores/workspace.js'
import { SidebarState } from './useSidebarState.js'
import { SidebarHandlers } from './useSidebarHandlers.js'
import { OpenTab } from './types.js'

export interface ProjectItemCallbacks {
  handleProjectToggleExpand: (e: React.MouseEvent, projectPath: string) => void
  handleProjectOpenSession: (
    projectPath: string,
    sessionId?: string,
    slug?: string,
    isNewSession?: boolean
  ) => void
  handleProjectRunExecutable: (projectPath: string) => Promise<void>
  handleProjectCloseProjectTabs: (projectPath: string) => void
  handleProjectContextMenu: (e: React.MouseEvent, project: Project) => void
  handleProjectItemDragStart: (e: React.DragEvent, projectPath: string) => void
  handleProjectItemDragOver: (e: React.DragEvent, projectPath: string) => void
  handleProjectItemDrop: (
    e: React.DragEvent,
    projectPath: string,
    categoryId: string | undefined
  ) => void
  handleProjectStartRename: (e: React.MouseEvent, project: Project) => void
  handleProjectEditingChange: (name: string) => void
  renderProjectItem: (project: Project) => React.ReactElement
}

export interface UseProjectItemCallbacksParams {
  state: SidebarState
  handlers: SidebarHandlers
  projects: Project[]
  openTabs: OpenTab[]
  onCloseProjectTabs: (projectPath: string) => void
}

export function useProjectItemCallbacks(
  params: UseProjectItemCallbacksParams
): Omit<ProjectItemCallbacks, 'renderProjectItem'> {
  const { state, handlers, projects, onCloseProjectTabs } = params
  const {
    toggleProject,
    handleOpenSession,
    setContextMenu,
    handleProjectDragStart,
    handleProjectDragOver,
    handleProjectDrop,
    handleProjectDragEnd,
    setEditingProject,
  } = state
  const { handleRunExecutable, handleStartRename } = handlers

  const handleProjectToggleExpand = useCallback(
    (e: React.MouseEvent, projectPath: string) => {
      toggleProject(e, projectPath)
    },
    [toggleProject]
  )

  const handleProjectOpenSession = useCallback(
    (projectPath: string, sessionId?: string, slug?: string, isNewSession?: boolean) => {
      handleOpenSession(projectPath, sessionId, slug, isNewSession)
    },
    [handleOpenSession]
  )

  const handleProjectRunExecutable = useCallback(
    async (projectPath: string) => {
      const project = projects.find((p) => p.path === projectPath)
      if (project) await handleRunExecutable(project)
    },
    [projects, handleRunExecutable]
  )

  const handleProjectCloseProjectTabs = useCallback(
    (projectPath: string) => {
      onCloseProjectTabs(projectPath)
    },
    [onCloseProjectTabs]
  )

  const handleProjectContextMenu = useCallback(
    (e: React.MouseEvent, project: Project) => {
      e.preventDefault()
      e.stopPropagation()
      setContextMenu({ x: e.clientX, y: e.clientY, project })
    },
    [setContextMenu]
  )

  const handleProjectItemDragStart = useCallback(
    (e: React.DragEvent, projectPath: string) => {
      handleProjectDragStart(e, projectPath)
    },
    [handleProjectDragStart]
  )

  const handleProjectItemDragOver = useCallback(
    (e: React.DragEvent, projectPath: string) => {
      const rect = e.currentTarget.getBoundingClientRect()
      const midY = rect.top + rect.height / 2
      const position = e.clientY < midY ? 'before' : 'after'
      handleProjectDragOver(e, projectPath, position)
    },
    [handleProjectDragOver]
  )

  const handleProjectItemDrop = useCallback(
    (e: React.DragEvent, projectPath: string, categoryId: string | undefined) => {
      handleProjectDrop(e, projectPath, categoryId)
    },
    [handleProjectDrop]
  )

  const handleProjectStartRename = useCallback(
    (e: React.MouseEvent, project: Project) => {
      handleStartRename(e, project)
    },
    [handleStartRename]
  )

  const handleProjectEditingChange = useCallback(
    (name: string) => {
      setEditingProject((prev) => (prev ? { ...prev, name } : null))
    },
    [setEditingProject]
  )

  return {
    handleProjectToggleExpand,
    handleProjectOpenSession,
    handleProjectRunExecutable,
    handleProjectCloseProjectTabs,
    handleProjectContextMenu,
    handleProjectItemDragStart,
    handleProjectItemDragOver,
    handleProjectItemDrop,
    handleProjectStartRename,
    handleProjectEditingChange,
  }
}

// Separate hook to get the memoization dependencies for renderProjectItem
export function useProjectItemDependencies(
  state: SidebarState,
  callbacks: Omit<ProjectItemCallbacks, 'renderProjectItem'>,
  handlers: SidebarHandlers,
  openTabs: OpenTab[]
): unknown[] {
  const {
    expandedProject,
    focusedProjectPath,
    draggedProject,
    editingProject,
    sessions,
    taskCounts,
    dropTarget,
    handleProjectDragEnd,
  } = state
  const { handleRenameSubmit, handleRenameKeyDown } = handlers

  return [
    expandedProject,
    focusedProjectPath,
    openTabs,
    draggedProject,
    editingProject,
    sessions,
    taskCounts,
    dropTarget,
    callbacks.handleProjectToggleExpand,
    callbacks.handleProjectOpenSession,
    callbacks.handleProjectRunExecutable,
    callbacks.handleProjectCloseProjectTabs,
    callbacks.handleProjectContextMenu,
    callbacks.handleProjectItemDragStart,
    handleProjectDragEnd,
    callbacks.handleProjectItemDragOver,
    callbacks.handleProjectItemDrop,
    callbacks.handleProjectStartRename,
    callbacks.handleProjectEditingChange,
    handleRenameSubmit,
    handleRenameKeyDown,
  ]
}

import { useState, useCallback, useRef } from 'react'
import { Project } from '../../../stores/workspace.js'
import { DropTarget } from '../types.js'

interface UseDragAndDropOptions {
  projects: Project[]
  moveProjectToCategory: (projectPath: string, categoryId: string | null) => void
  reorderProjects: (categoryId: string | null, projectPaths: string[]) => void
  reorderCategories: (categoryIds: string[]) => void
  categories: Array<{ id: string; name: string; order: number; collapsed?: boolean }>
}

interface UseDragAndDropReturn {
  draggedProject: string | null
  draggedCategory: string | null
  dropTarget: DropTarget | null
  handleProjectDragStart: (e: React.DragEvent, projectPath: string) => void
  handleProjectDragEnd: () => void
  handleCategoryDragOver: (e: React.DragEvent, categoryId: string | null) => void
  handleCategoryDrop: (e: React.DragEvent, categoryId: string | null) => void
  handleProjectDragOver: (
    e: React.DragEvent,
    projectPath: string,
    position: 'before' | 'after'
  ) => void
  handleProjectDrop: (
    e: React.DragEvent,
    targetPath: string,
    targetCategoryId: string | undefined
  ) => void
  handleCategoryDragStart: (e: React.DragEvent, categoryId: string) => void
  handleCategoryDragEnd: () => void
  handleCategoryHeaderDragOver: (
    e: React.DragEvent,
    targetCategoryId: string,
    position: 'before' | 'after'
  ) => void
  handleCategoryHeaderDrop: (e: React.DragEvent, targetCategoryId: string) => void
}

export function useDragAndDrop({
  projects,
  moveProjectToCategory,
  reorderProjects,
  reorderCategories,
  categories,
}: UseDragAndDropOptions): UseDragAndDropReturn {
  const [draggedProject, setDraggedProject] = useState<string | null>(null)
  const [draggedCategory, setDraggedCategory] = useState<string | null>(null)
  const [dropTarget, setDropTarget] = useState<DropTarget | null>(null)
  // Ref tracks the latest dropTarget so drop handlers always read fresh position
  // (state in the closure may be stale if React hasn't re-rendered since the last dragOver)
  const dropTargetRef = useRef<DropTarget | null>(null)

  const handleProjectDragStart = useCallback((e: React.DragEvent, projectPath: string) => {
    setDraggedProject(projectPath)
    e.dataTransfer.effectAllowed = 'move'
    e.dataTransfer.setData('text/plain', projectPath)
    // Also set custom type so TiledTerminalView can detect sidebar project drags
    e.dataTransfer.setData('application/x-sidebar-project', projectPath)
  }, [])

  const handleProjectDragEnd = useCallback(() => {
    setDraggedProject(null)
    setDropTarget(null)
    dropTargetRef.current = null
  }, [])

  const handleCategoryDragOver = useCallback(
    (e: React.DragEvent, categoryId: string | null) => {
      e.preventDefault()
      e.dataTransfer.dropEffect = 'move'
      if (draggedProject) {
        const target: DropTarget = {
          type: categoryId ? 'category' : 'uncategorized',
          id: categoryId,
        }
        setDropTarget(target)
        dropTargetRef.current = target
      }
    },
    [draggedProject]
  )

  const handleCategoryDrop = useCallback(
    (e: React.DragEvent, categoryId: string | null) => {
      e.preventDefault()
      if (draggedProject) {
        moveProjectToCategory(draggedProject, categoryId)
      }
      setDraggedProject(null)
      setDropTarget(null)
      dropTargetRef.current = null
    },
    [draggedProject, moveProjectToCategory]
  )

  const handleProjectDragOver = useCallback(
    (e: React.DragEvent, projectPath: string, position: 'before' | 'after') => {
      e.preventDefault()
      e.stopPropagation()
      e.dataTransfer.dropEffect = 'move'
      if (draggedProject && draggedProject !== projectPath) {
        const target: DropTarget = { type: 'project', id: projectPath, position }
        setDropTarget(target)
        dropTargetRef.current = target
      }
    },
    [draggedProject]
  )

  const handleProjectDrop = useCallback(
    (e: React.DragEvent, targetPath: string, targetCategoryId: string | undefined) => {
      e.preventDefault()
      e.stopPropagation()

      if (draggedProject && draggedProject !== targetPath) {
        const draggedProjectData = projects.find((p) => p.path === draggedProject)
        const targetProject = projects.find((p) => p.path === targetPath)

        if (draggedProjectData && targetProject) {
          moveProjectToCategory(draggedProject, targetCategoryId ?? null)
          const categoryProjects = projects
            .filter((p) =>
              targetCategoryId ? p.categoryId === targetCategoryId : !p.categoryId
            )
            .sort((a, b) => (a.order ?? 0) - (b.order ?? 0))
            .map((p) => p.path)

          const newOrder = categoryProjects.filter((p) => p !== draggedProject)
          const targetIndex = newOrder.indexOf(targetPath)
          // Read from ref to get the latest position (state may be stale)
          const currentDropTarget = dropTargetRef.current
          const insertIndex = currentDropTarget?.position === 'after' ? targetIndex + 1 : targetIndex
          newOrder.splice(insertIndex, 0, draggedProject)
          reorderProjects(targetCategoryId ?? null, newOrder)
        }
      }
      setDraggedProject(null)
      setDropTarget(null)
      dropTargetRef.current = null
    },
    [draggedProject, projects, moveProjectToCategory, reorderProjects]
  )

  const handleCategoryDragStart = useCallback((e: React.DragEvent, categoryId: string) => {
    setDraggedCategory(categoryId)
    e.dataTransfer.effectAllowed = 'move'
    e.dataTransfer.setData('text/plain', categoryId)
  }, [])

  const handleCategoryDragEnd = useCallback(() => {
    setDraggedCategory(null)
    setDropTarget(null)
    dropTargetRef.current = null
  }, [])

  const handleCategoryHeaderDragOver = useCallback(
    (e: React.DragEvent, targetCategoryId: string, position: 'before' | 'after') => {
      e.preventDefault()
      e.dataTransfer.dropEffect = 'move'
      if (draggedCategory && draggedCategory !== targetCategoryId) {
        const target: DropTarget = { type: 'category', id: targetCategoryId, position }
        setDropTarget(target)
        dropTargetRef.current = target
      }
    },
    [draggedCategory]
  )

  const handleCategoryHeaderDrop = useCallback(
    (e: React.DragEvent, targetCategoryId: string) => {
      e.preventDefault()
      if (draggedCategory && draggedCategory !== targetCategoryId) {
        const orderedCategories = [...categories].sort((a, b) => a.order - b.order)
        const categoryIds = orderedCategories.map((c) => c.id)
        const newOrder = categoryIds.filter((id) => id !== draggedCategory)
        const targetIndex = newOrder.indexOf(targetCategoryId)
        // Read from ref to get the latest position (state may be stale)
        const currentDropTarget = dropTargetRef.current
        const insertIndex = currentDropTarget?.position === 'after' ? targetIndex + 1 : targetIndex
        newOrder.splice(insertIndex, 0, draggedCategory)
        reorderCategories(newOrder)
      }
      setDraggedCategory(null)
      setDropTarget(null)
      dropTargetRef.current = null
    },
    [draggedCategory, categories, reorderCategories]
  )

  return {
    draggedProject,
    draggedCategory,
    dropTarget,
    handleProjectDragStart,
    handleProjectDragEnd,
    handleCategoryDragOver,
    handleCategoryDrop,
    handleProjectDragOver,

import { app } from 'electron'
import { existsSync, mkdirSync, readFileSync, writeFileSync, renameSync, statSync } from 'fs'
import { join } from 'path'
import { syncMetaProjects } from './meta-project-sync'

export interface ProjectCategory {
  id: string
  name: string
  collapsed: boolean
  order: number
}

export interface Project {
  path: string
  name: string
  executable?: string
  apiPort?: number  // Port for HTTP API to send prompts to terminal
  apiAutoStart?: boolean  // Whether to auto-start API when session opens (default: false)
  apiSessionMode?: 'existing' | 'new-keep' | 'new-close'  // How API requests handle sessions
  apiModel?: 'default' | 'opus' | 'sonnet' | 'haiku'  // Model for API-triggered sessions
  autoAcceptTools?: string[]  // Per-project tool patterns to auto-accept
  permissionMode?: string     // Per-project permission mode
  color?: string              // Project color for visual identification
  ttsVoice?: string           // Per-project TTS voice (overrides global)
  ttsEngine?: 'piper' | 'xtts'  // Per-project TTS engine
  backend?: 'default' | 'claude' | 'gemini' | 'codex' | 'opencode' | 'aider' // Per-project backend (overrides global)
  categoryId?: string         // Category this project belongs to
  order?: number              // Order within category or uncategorized list
}

export interface OpenTab {
  id: string
  projectPath: string
  sessionId?: string
  title: string
  ptyId?: string
  backend?: 'default' | 'claude' | 'gemini' | 'codex' | 'opencode' | 'aider'
}

export interface TileLayout {
  id: string
  tabIds: string[]
  activeTabId: string
  x: number
  y: number
  width: number
  height: number
}

export interface Workspace {
  projects: Project[]
  openTabs: OpenTab[]
  activeTabId: string | null
  viewMode?: 'tabs' | 'tiled'
  tileLayout?: TileLayout[]
  categories?: ProjectCategory[]
}

export interface WindowBounds {
  x: number
  y: number
  width: number
  height: number
}

export interface ThemeCustomization {
  accentColor: string | null
  backgroundColor: string | null
  textColor: string | null
  terminalColors: {
    black?: string
    red?: string
    green?: string
    yellow?: string
    blue?: string
    magenta?: string
    cyan?: string
    white?: string
  } | null
}

export interface Settings {
  defaultProjectDir: string
  theme: string
  themeCustomization?: ThemeCustomization | null
  voiceOutputEnabled?: boolean
  voiceVolume?: number
  voiceSpeed?: number
  voiceSkipOnNew?: boolean
  voiceSilenceThreshold?: number
  autoAcceptTools?: string[]
  permissionMode?: string
  backend?: 'default' | 'claude' | 'gemini' | 'codex' | 'opencode' | 'aider'
}


interface StoredData {
  workspace: Workspace
  windowBounds?: WindowBounds
  settings?: Settings
}

export class SessionStore {
  private configPath: string
  private backupPath: string
  private data: StoredData

  constructor() {
    const configDir = join(app.getPath('userData'), 'config')
    if (!existsSync(configDir)) {
      mkdirSync(configDir, { recursive: true })
    }
    this.configPath = join(configDir, 'workspace.json')
    this.backupPath = join(configDir, 'workspace.json.backup')
    this.data = this.load()
  }

  private loadFile(path: string): StoredData | null {
    try {
      if (!existsSync(path)) return null
      const stat = statSync(path)
      if (stat.size === 0) return null
      const content = readFileSync(path, 'utf-8')
      const data = JSON.parse(content)
      if (!data?.workspace) return null
      return data
    } catch (e) {
      console.error(`[SessionStore] Failed to load ${path}:`, e)
      return null
    }
  }

  private load(): StoredData {
    // Try main file first
    const main = this.loadFile(this.configPath)
    if (main && (main.workspace.projects?.length || 0) > 0) {
      return main
    }

    // Main file is empty/corrupt/missing — try backup
    const backup = this.loadFile(this.backupPath)
    if (backup && (backup.workspace.projects?.length || 0) > 0) {
      console.log('[SessionStore] Main config empty/corrupt, restored from backup (' +
        backup.workspace.projects.length + ' projects)')
      // Restore backup as main file immediately
      try {
        writeFileSync(this.configPath, JSON.stringify(backup, null, 2))
      } catch (e) {
        console.error('[SessionStore] Failed to restore backup to main:', e)
      }
      return backup
    }

    // If main loaded but had 0 projects (valid empty state), use it
    if (main) return main

    return {
      workspace: {
        projects: [],
        openTabs: [],
        activeTabId: null
      }
    }
  }

  private save(): void {
    try {
      const json = JSON.stringify(this.data, null, 2)

      // Validate we can parse what we're about to write
      JSON.parse(json)

      // Back up existing file before overwriting (if it has content)
      if (existsSync(this.configPath)) {
        try {
          const stat = statSync(this.configPath)
          if (stat.size > 0) {
            // Only update backup if existing file is valid and has projects
            const existing = this.loadFile(this.configPath)
            if (existing && (existing.workspace.projects?.length || 0) > 0) {
              writeFileSync(this.backupPath, readFileSync(this.configPath))
            }
          }
        } catch (e) {
          console.error('[SessionStore] Failed to update backup:', e)
        }
      }

      // Atomic write: write to temp file, then rename
      const tmpPath = this.configPath + '.tmp'
      writeFileSync(tmpPath, json)

      // Verify the temp file was written completely
      const written = readFileSync(tmpPath, 'utf-8')
      JSON.parse(written) // throws if truncated/corrupt

      renameSync(tmpPath, this.configPath)
    } catch (e) {
      console.error('[SessionStore] Failed to save workspace:', e)
    }
  }

  getWorkspace(): Workspace {
    return this.data.workspace
  }

  // Reload workspace from disk (useful when file was modified externally)
  reloadFromDisk(): void {
    console.log('[SessionStore] Reloading workspace from disk')
    this.data = this.load()
    console.log('[SessionStore] Reloaded, projects:', this.data.workspace?.projects?.length || 0)
  }

  saveWorkspace(workspace: Workspace): void {
    // Protect against overwriting populated workspace with empty one
    const incomingProjects = workspace?.projects?.length || 0
    const currentProjects = this.data.workspace?.projects?.length || 0
    if (incomingProjects === 0 && currentProjects > 0) {
      console.log('[SessionStore] Rejected empty workspace save - current has', currentProjects, 'projects')
      return
    }
    this.data.workspace = workspace
    this.save()
    syncMetaProjects(workspace)
  }

  getWindowBounds(): WindowBounds | undefined {
    return this.data.windowBounds
  }

  saveWindowBounds(bounds: WindowBounds): void {
    this.data.windowBounds = bounds
    this.save()
  }

  getSettings(): Settings {
    return this.data.settings ?? { defaultProjectDir: '', theme: 'default', backend: 'default' }
  }

  saveSettings(settings: Settings): void {
    this.data.settings = settings
    this.save()
  }
}

