import { useState, useCallback } from 'react'
import { TileLayout } from '../components/TiledTerminalView'

type ViewMode = 'tabs' | 'tiled'

interface UseViewStateReturn {
  viewMode: ViewMode
  tileLayout: TileLayout[]
  lastFocusedTabId: string | null
  sidebarWidth: number
  sidebarCollapsed: boolean
  setViewMode: (mode: ViewMode) => void
  setTileLayout: (layout: TileLayout[]) => void
  setLastFocusedTabId: (id: string | null) => void
  setSidebarWidth: (width: number) => void
  setSidebarCollapsed: (collapsed: boolean) => void
  toggleViewMode: () => void
}

export function useViewState(): UseViewStateReturn {
  const [viewMode, setViewModeState] = useState<ViewMode>('tabs')
  const [tileLayout, setTileLayout] = useState<TileLayout[]>([])
  const [lastFocusedTabId, setLastFocusedTabId] = useState<string | null>(null)
  const [sidebarWidth, setSidebarWidth] = useState(280)
  const [sidebarCollapsed, setSidebarCollapsed] = useState(false)

  const setViewMode = useCallback((mode: ViewMode) => {
    setViewModeState(mode)
    // Trigger resize events to force terminals to refit after view mode change
    setTimeout(() => window.dispatchEvent(new Event('resize')), 50)
    setTimeout(() => window.dispatchEvent(new Event('resize')), 150)
    setTimeout(() => window.dispatchEvent(new Event('resize')), 300)
  }, [])

  const toggleViewMode = useCallback(() => {
    setViewMode(viewMode === 'tabs' ? 'tiled' : 'tabs')
  }, [viewMode, setViewMode])

  return {
    viewMode,
    tileLayout,
    lastFocusedTabId,
    sidebarWidth,
    sidebarCollapsed,
    setViewMode,
    setTileLayout,
    setLastFocusedTabId,
    setSidebarWidth,
    setSidebarCollapsed,
    toggleViewMode
  }
}

import { useEffect, useRef, useState, useCallback } from 'react'
import type { Api } from '../api'
import type { BackendId } from '../api/types'
import type { AppSettings } from './useSettings'
import { useWorkspaceStore } from '../stores/workspace'
import { Theme, getThemeById, applyTheme, themes } from '../themes'
import { cleanupOrphanedBuffers } from '../components/terminal/Terminal'

interface UseWorkspaceLoaderOptions {
  api: Api
  checkInstallation: () => Promise<void>
  setViewMode: (mode: 'tabs' | 'tiled') => void
  setTileLayout: (layout: any[]) => void
}

interface UseWorkspaceLoaderReturn {
  loading: boolean
  currentTheme: Theme
  settings: AppSettings | null
  setCurrentTheme: (theme: Theme) => void
  setSettings: (settings: AppSettings | null) => void
}

export function useWorkspaceLoader({
  api,
  checkInstallation,
  setViewMode,
  setTileLayout
}: UseWorkspaceLoaderOptions): UseWorkspaceLoaderReturn {
  const {
    setProjects,
    setCategories,
    addTab,
    clearTabs
  } = useWorkspaceStore()

  const [loading, setLoading] = useState(true)
  const [currentTheme, setCurrentTheme] = useState<Theme>(themes[0])
  const [settings, setSettings] = useState<AppSettings | null>(null)
  const initRef = useRef(false)
  const hadProjectsRef = useRef(false)

  // Load workspace on mount and restore tabs
  useEffect(() => {
    // Prevent double initialization from StrictMode
    if (initRef.current) return
    initRef.current = true

    const loadWorkspace = async () => {
      try {
        // Check if Claude, npm, and git-bash are installed
        await checkInstallation()

        // Load and apply theme with any saved customizations
        const loadedSettings = await api.getSettings()
        setSettings(loadedSettings)
        const theme = getThemeById(loadedSettings.theme || 'default')
        applyTheme(theme, loadedSettings.themeCustomization)
        setCurrentTheme(theme)

        // Kill any existing PTYs from hot reload (but don't clear buffers - they'll be restored)
        const existingTabs = useWorkspaceStore.getState().openTabs
        for (const tab of existingTabs) {
          api.killPty(tab.id)
        }
        clearTabs()

        const workspace = await api.getWorkspace()
        if (workspace.projects) {
          setProjects(workspace.projects)
          if (workspace.projects.length > 0) {
            hadProjectsRef.current = true
          }
          // Install TTS instructions for all existing projects
          for (const project of workspace.projects) {
            await api.ttsInstallInstructions?.(project.path)
          }
        }
        // Load categories
        if (workspace.categories) {
          setCategories(workspace.categories)
        }

        // Restore previously open tabs (only if not already open)
        // Track old ID -> new ID mapping for layout restoration
        const idMapping = new Map<string, string>()

        if (workspace.openTabs && workspace.openTabs.length > 0) {
          const currentTabs = useWorkspaceStore.getState().openTabs
          const usedSessionIds = new Set(currentTabs.map(t => t.sessionId).filter(Boolean))
          const sessionsCache = new Map<string, { list: { sessionId: string; slug: string }[]; nextIndex: number }>()

          for (const savedTab of workspace.openTabs) {
            try {
              // Always install TTS instructions so Claude uses <tts> tags
              await api.ttsInstallInstructions?.(savedTab.projectPath)

              const projectName = savedTab.projectPath.split(/[/\\]/).pop() || savedTab.projectPath
              let titleToRestore = savedTab.title || `${projectName} - New`

              // Get project and determine effective backend for restored tab
              const projectForTab = workspace.projects?.find((p: { path: string }) => p.path === savedTab.projectPath)
              const savedBackend = savedTab.backend
              const effectiveBackendForTab = (savedBackend
                || (projectForTab?.backend && projectForTab.backend !== 'default'
                  ? projectForTab.backend
                  : (loadedSettings?.backend && loadedSettings.backend !== 'default'
                    ? loadedSettings.backend
                    : 'claude'))) as BackendId

              let sessionIdToRestore: string | undefined = savedTab.sessionId

              // Always discover sessions to find the most recent one
              let sessionsForProject = sessionsCache.get(savedTab.projectPath)
              if (!sessionsForProject) {
                const list = await api.discoverSessions(savedTab.projectPath, effectiveBackendForTab)
                sessionsForProject = { list, nextIndex: 0 }
                sessionsCache.set(savedTab.projectPath, sessionsForProject)
              }

              const list = sessionsForProject.list || []
              for (let i = sessionsForProject.nextIndex; i < list.length; i++) {
                const candidate = list[i]
                if (!usedSessionIds.has(candidate.sessionId)) {
                  sessionIdToRestore = candidate.sessionId
                  titleToRestore = `${projectName} - ${candidate.slug}`
                  sessionsForProject.nextIndex = i + 1
                  break
                }
              }

              const ptyId = await api.spawnPty(
                savedTab.projectPath,
                sessionIdToRestore,
                undefined,
                effectiveBackendForTab
              )
              if (savedTab.id) {
                idMapping.set(savedTab.id, ptyId)
              }

              addTab({
                id: ptyId,
                projectPath: savedTab.projectPath,
                sessionId: sessionIdToRestore,
                title: titleToRestore,
                ptyId,
                backend: effectiveBackendForTab
              })
              if (sessionIdToRestore) {
                usedSessionIds.add(sessionIdToRestore)
              }
            } catch (e) {
              console.error('Failed to restore tab:', savedTab.projectPath, e)
            }
          }
        }

        // Clean up orphaned terminal buffers from previous session/HMR
        const activeTabIds = useWorkspaceStore.getState().openTabs.map(t => t.id)
        cleanupOrphanedBuffers(activeTabIds)

        // Restore view mode
        if (workspace.viewMode) {
          setViewMode(workspace.viewMode)
        }
        // Restore tileLayout with mapped IDs and migrate legacy format
        if (workspace.tileLayout && workspace.tileLayout.length > 0 && idMapping.size > 0) {
          const mappedLayout = workspace.tileLayout
            .map(tile => {
              // Migrate legacy tiles: add tabIds/activeTabId if missing
              const tabIds = tile.tabIds || [tile.id]
              const mappedTabIds = tabIds
                .map(id => idMapping.get(id) || id)
                .filter(id => {
                  // Only keep tab IDs that exist in the current session
                  const currentTabs = useWorkspaceStore.getState().openTabs
                  return currentTabs.some(t => t.id === id)
                })

              if (mappedTabIds.length === 0) return null

              const newId = idMapping.get(tile.id) || mappedTabIds[0]
              const activeTabId = tile.activeTabId
                ? (idMapping.get(tile.activeTabId) || mappedTabIds[0])
                : mappedTabIds[0]

              return {
                ...tile,
                id: newId,
                tabIds: mappedTabIds,
                activeTabId
              }
            })
            .filter((tile): tile is NonNullable<typeof tile> => tile !== null)

          if (mappedLayout.length > 0) {
            setTileLayout(mappedLayout)
          }
        }
      } catch (e) {
        console.error('Failed to load workspace:', e)
      }
      setLoading(false)
    }
    loadWorkspace()
  }, [api, addTab, clearTabs, checkInstallation, setProjects, setCategories, setViewMode, setTileLayout])

  return {
    loading,
    currentTheme,
    settings,
    setCurrentTheme,
    setSettings
  }
}

import { create } from 'zustand'
import { clearProjectCaches } from '../utils/lruCache'

export interface ProjectCategory {
  id: string
  name: string
  collapsed: boolean
  order: number
}

export interface Project {
  path: string
  name: string
  executable?: string
  apiPort?: number
  apiAutoStart?: boolean
  apiSessionMode?: 'existing' | 'new-keep' | 'new-close'
  apiModel?: 'default' | 'opus' | 'sonnet' | 'haiku'
  autoAcceptTools?: string[]
  permissionMode?: string
  color?: string
  ttsVoice?: string
  ttsEngine?: 'piper' | 'xtts'
  backend?: 'default' | 'claude' | 'gemini' | 'codex' | 'opencode' | 'aider'
  categoryId?: string
  order?: number
}

export interface OpenTab {
  id: string
  projectPath: string
  sessionId?: string
  title: string
  ptyId: string
  backend?: 'default' | 'claude' | 'gemini' | 'codex' | 'opencode' | 'aider'
}

interface WorkspaceState {
  projects: Project[]
  openTabs: OpenTab[]
  activeTabId: string | null
  categories: ProjectCategory[]

  setProjects: (projects: Project[]) => void
  addProject: (project: Project) => void
  removeProject: (path: string) => void
  updateProject: (path: string, updates: Partial<Project>) => void

  addTab: (tab: OpenTab) => void
  removeTab: (id: string) => void
  updateTab: (id: string, updates: Partial<OpenTab>) => void
  setActiveTab: (id: string) => void
  clearTabs: () => void

  setCategories: (categories: ProjectCategory[]) => void
  addCategory: (name: string) => string
  updateCategory: (id: string, updates: Partial<ProjectCategory>) => void
  removeCategory: (id: string) => void
  reorderCategories: (ids: string[]) => void
  moveProjectToCategory: (projectPath: string, categoryId: string | null) => void
  reorderProjects: (categoryId: string | null, projectPaths: string[]) => void
}

const generateCategoryId = (): string =>
  `cat-${Date.now()}-${Math.random().toString(36).substr(2, 9)}`

export const useWorkspaceStore = create<WorkspaceState>((set, get) => ({
  projects: [],
  openTabs: [],
  activeTabId: null,
  categories: [],

  setProjects: (projects) => set({ projects }),

  addProject: (project) => {
    const { projects } = get()
    if (!projects.find((p) => p.path === project.path)) {
      set({ projects: [...projects, project] })
    }
  },

  removeProject: (path) => {
    const { projects } = get()
    clearProjectCaches(path)
    set({ projects: projects.filter((p) => p.path !== path) })
  },

  updateProject: (path, updates) => {
    const { projects } = get()
    set({
      projects: projects.map((p) =>
        p.path === path ? { ...p, ...updates } : p
      )
    })
  },

  addTab: (tab) => {
    const { openTabs } = get()
    set({
      openTabs: [...openTabs, tab],
      activeTabId: tab.id
    })
  },

  removeTab: (id) => {
    const { openTabs, activeTabId } = get()
    const newTabs = openTabs.filter((t) => t.id !== id)
    let newActiveId = activeTabId

    if (activeTabId === id) {
      const index = openTabs.findIndex((t) => t.id === id)
      if (newTabs.length > 0) {
        newActiveId = newTabs[Math.min(index, newTabs.length - 1)].id
      } else {
        newActiveId = null
      }
    }

    set({ openTabs: newTabs, activeTabId: newActiveId })
  },

  updateTab: (id, updates) => {
    const { openTabs } = get()
    set({
      openTabs: openTabs.map((t) =>
        t.id === id ? { ...t, ...updates } : t
      )
    })
  },

  setActiveTab: (id) => set({ activeTabId: id }),

  clearTabs: () => set({ openTabs: [], activeTabId: null }),

  setCategories: (categories) => set({ categories }),

  addCategory: (name) => {
    const { categories } = get()
    const id = generateCategoryId()
    const maxOrder = categories.reduce((max, c) => Math.max(max, c.order), -1)
    set({
      categories: [...categories, { id, name, collapsed: false, order: maxOrder + 1 }]
    })
    return id
  },

  updateCategory: (id, updates) => {
    const { categories } = get()
    set({
      categories: categories.map((c) =>
        c.id === id ? { ...c, ...updates } : c
      )
    })
  },

  removeCategory: (id) => {
    const { categories, projects } = get()
    set({
      categories: categories.filter((c) => c.id !== id),
      projects: projects.map((p) =>
        p.categoryId === id ? { ...p, categoryId: undefined } : p
      )
    })
  },

  reorderCategories: (ids) => {
    const { categories } = get()
    set({
      categories: categories.map((c) => ({
        ...c,
        order: ids.indexOf(c.id)
      }))
    })
  },

  moveProjectToCategory: (projectPath, categoryId) => {
    const { projects } = get()
    const categoryProjects = projects.filter((p) =>
      categoryId === null ? !p.categoryId : p.categoryId === categoryId
    )
    const maxOrder = categoryProjects.reduce((max, p) => Math.max(max, p.order ?? -1), -1)
    set({
      projects: projects.map((p) =>
        p.path === projectPath
          ? { ...p, categoryId: categoryId ?? undefined, order: maxOrder + 1 }
          : p
      )
    })
  },

  reorderProjects: (categoryId, projectPaths) => {
    const { projects } = get()
    set({
      projects: projects.map((p) => {
        const index = projectPaths.indexOf(p.path)
        if (index >= 0) {
          return { ...p, order: index }
        }
        return p
      })
    })
  }
}))

import React, { useState, useEffect } from 'react'
import type { Theme } from '../themes'
import { VoiceBrowserModal } from './VoiceBrowserModal'
import { useVoice } from '../contexts/VoiceContext'
import { useFocusTrap } from '../hooks/useFocusTrap'
import {
  ThemeSettings,
  ProjectDirectorySettings,
  PermissionsSettings,
  BackendSettings,
  ExtensionsSettings,
  VoiceInputSettings,
  VoiceOutputSettings,
  UninstallTTSSection,
  VersionSettings,
  DEFAULT_GENERAL,
  DEFAULT_VOICE,
  DEFAULT_XTTS,
  DEFAULT_UI,
  DEFAULT_THEME_CUSTOMIZATION,
} from './settings'
import type {
  GeneralSettings,
  VoiceSettings,
  XttsSettings,
  UIState,
  SettingsModalProps,
  ThemeCustomization,
} from './settings'

// Migrate old slider-based customization to new color-based format
function migrateThemeCustomization(saved: unknown): ThemeCustomization {
  if (!saved || typeof saved !== 'object') return DEFAULT_THEME_CUSTOMIZATION
  const obj = saved as Record<string, unknown>
  // Old format had terminalSaturation/backgroundBrightness — discard and use defaults
  if ('terminalSaturation' in obj || 'backgroundBrightness' in obj) {
    return {
      accentColor: (typeof obj.accentColor === 'string' ? obj.accentColor : null),
      backgroundColor: null,
      textColor: null,
      terminalColors: null
    }
  }
  return {
    accentColor: (typeof obj.accentColor === 'string' ? obj.accentColor : null),
    backgroundColor: (typeof obj.backgroundColor === 'string' ? obj.backgroundColor : null),
    textColor: (typeof obj.textColor === 'string' ? obj.textColor : null),
    terminalColors: (obj.terminalColors && typeof obj.terminalColors === 'object' ? obj.terminalColors as ThemeCustomization['terminalColors'] : null)
  }
}

export function SettingsModal({
  isOpen,
  onClose,
  onThemeChange,
  onSaved,
  appVersion,
  updateStatus,
  onDownloadUpdate,
  onInstallUpdate
}: SettingsModalProps): React.ReactElement | null {
  // Grouped state: general settings (theme, directory, permissions, backend)
  const [general, setGeneral] = useState<GeneralSettings>(DEFAULT_GENERAL)

  // Focus trap for modal accessibility
  const focusTrapRef = useFocusTrap<HTMLDivElement>(isOpen)

  // Voice context for active whisper model and volume
  const { whisperModel: activeWhisperModel, setWhisperModel: setActiveWhisperModel, volume: voiceVolume } = useVoice()

  // Extensions state
  const [installedExtensions, setInstalledExtensions] = useState<Array<{ id: string; name: string; type: string }>>([])

  // Grouped state: voice settings (TTS, whisper status, selected voice/engine)
  const [voice, setVoice] = useState<VoiceSettings>(DEFAULT_VOICE)

  // Grouped state: XTTS quality settings
  const [xtts, setXtts] = useState<XttsSettings>(DEFAULT_XTTS)

  // Grouped state: UI/loading states
  const [ui, setUI] = useState<UIState>(DEFAULT_UI)

  // Load installed voices (Piper and XTTS)
  async function refreshInstalledVoices(): Promise<void> {
    try {
      const [piperVoices, xttsVoices] = await Promise.all([
        window.electronAPI?.voiceGetInstalled?.(),
        window.electronAPI?.xttsGetVoices?.()
      ])
      const combined: Array<{ key: string; displayName: string; source: string }> = []
      if (piperVoices) combined.push(...piperVoices)
      if (xttsVoices) {
        combined.push(...xttsVoices.map((v: { id: string; name: string }) => ({
          key: v.id,
          displayName: v.name,
          source: 'xtts'
        })))
      }
      setVoice(prev => ({ ...prev, installedVoices: combined }))
    } catch (e) {
      console.error('Failed to refresh installed voices:', e)
      setVoice(prev => ({ ...prev, installedVoices: [] }))
    }
  }

  useEffect(() => {
    if (isOpen) {
      window.electronAPI?.getSettings?.()?.then((settings) => {
        setGeneral(prev => ({
          ...prev,
          defaultProjectDir: settings.defaultProjectDir || '',
          selectedTheme: settings.theme || 'default',
          themeCustomization: migrateThemeCustomization(settings.themeCustomization),
          autoAcceptTools: settings.autoAcceptTools || [],
          permissionMode: settings.permissionMode || 'default',
          backend: settings.backend || 'default'
        }))
      })

      // Load voice settings (active voice)
      window.electronAPI?.voiceGetSettings?.()?.then((voiceSettings: { ttsVoice?: string; ttsEngine?: string; ttsSpeed?: number; xttsTemperature?: number; xttsTopK?: number; xttsTopP?: number; xttsRepetitionPenalty?: number }) => {
        if (voiceSettings) {
          setVoice(prev => ({
            ...prev,
            selectedVoice: voiceSettings.ttsVoice || 'en_US-libritts_r-medium',
            selectedEngine: (voiceSettings.ttsEngine as 'piper' | 'xtts') || 'piper',
            ttsSpeed: voiceSettings.ttsSpeed || 1.0
          }))
          setXtts({
            temperature: voiceSettings.xttsTemperature ?? 0.65,
            topK: voiceSettings.xttsTopK ?? 50,
            topP: voiceSettings.xttsTopP ?? 0.85,
            repetitionPenalty: voiceSettings.xttsRepetitionPenalty ?? 2.0
          })
        }
      })?.catch(e => console.error('Failed to load voice settings:', e))

      // Load voice status
      window.electronAPI?.voiceCheckWhisper?.()?.then((status) => {
        setVoice((prev) => ({ ...prev, whisperStatus: status }))
      })?.catch((e) => console.error('Failed to check Whisper status:', e))

      window.electronAPI?.voiceCheckTTS?.()?.then((status) => {
        setVoice((prev) => ({ ...prev, ttsStatus: status }))
      })?.catch((e) => console.error('Failed to check TTS status:', e))

      refreshInstalledVoices()

      // Load installed extensions
      window.electronAPI?.extensionsGetInstalled?.()?.then((exts) => {
        setInstalledExtensions(exts || [])
      })?.catch((e) => console.error('Failed to load installed extensions:', e))
    } else {
      setUI(prev => ({ ...prev, playingPreview: null, previewLoading: null }))
    }
  }, [isOpen])

  async function handleSave(): Promise<void> {
    const newSettings = {
      defaultProjectDir: general.defaultProjectDir,
      theme: general.selectedTheme,
      themeCustomization: general.themeCustomization,
      autoAcceptTools: general.autoAcceptTools,
      permissionMode: general.permissionMode,
      backend: general.backend
    }
    await window.electronAPI?.saveSettings(newSettings)
    // Save voice settings including XTTS quality settings
    await window.electronAPI?.voiceApplySettings?.({
      ttsVoice: voice.selectedVoice,
      ttsEngine: voice.selectedEngine,
      ttsSpeed: voice.ttsSpeed,
      xttsTemperature: xtts.temperature,
      xttsTopK: xtts.topK,
      xttsTopP: xtts.topP,
      xttsRepetitionPenalty: xtts.repetitionPenalty
    })
    onSaved?.(newSettings)
    onClose()
  }

  function handleVoiceSelect(voiceKey: string, source: string): void {
    setVoice(prev => ({
      ...prev,
      selectedVoice: voiceKey,
      selectedEngine: source === 'xtts' ? 'xtts' : 'piper'
    }))
  }

  function toggleTool(tool: string): void {
    setGeneral(prev => ({
      ...prev,
      autoAcceptTools: prev.autoAcceptTools.includes(tool)
        ? prev.autoAcceptTools.filter(t => t !== tool)
        : [...prev.autoAcceptTools, tool]
    }))
  }

  function addCustomTool(): void {
    const trimmed = general.customTool.trim()
    if (trimmed && !general.autoAcceptTools.includes(trimmed)) {
      setGeneral(prev => ({
        ...prev,
        autoAcceptTools: [...prev.autoAcceptTools, trimmed],
        customTool: ''
      }))
    }
  }

  function removeCustomTool(tool: string): void {
    setGeneral(prev => ({
      ...prev,
      autoAcceptTools: prev.autoAcceptTools.filter(t => t !== tool)
    }))
  }

  async function handleInstallWhisperModel(model: string): Promise<void> {
    setUI(prev => ({ ...prev, installingModel: model }))
    try {
      await window.electronAPI?.voiceInstallWhisper?.(model)
      const status = await window.electronAPI?.voiceCheckWhisper?.()
      if (status) setVoice(prev => ({ ...prev, whisperStatus: status }))
    } catch (e) {
      console.error('Failed to install Whisper model:', e)
    }
    setUI(prev => ({ ...prev, installingModel: null }))
  }

  // Remove TTS instructions from all projects (uninstall feature)
  async function handleRemoveTTSFromAllProjects(): Promise<void> {
    if (!confirm('This will remove TTS voice output instructions from CLAUDE.md files in ALL your projects. This is useful if you want to stop using Claude Terminal.\n\nContinue?')) {
      return
    }

    setUI(prev => ({ ...prev, removingTTS: true, ttsRemovalResult: null }))

    try {
      const workspace = await window.electronAPI?.getWorkspace()
      const projects = workspace?.projects || []

      let success = 0
      let failed = 0

      for (const project of projects) {
        try {
          const result = await window.electronAPI?.ttsRemoveInstructions?.(project.path)
          if (result?.success) {
            success++
          } else {
            failed++
          }
        } catch {
          failed++
        }
      }

      setUI(prev => ({ ...prev, ttsRemovalResult: { success, failed } }))
    } catch (e) {
      console.error('Failed to remove TTS instructions:', e)
      setUI(prev => ({ ...prev, ttsRemovalResult: { success: 0, failed: 1 } }))
    }

    setUI(prev => ({ ...prev, removingTTS: false }))
  }

  if (!isOpen) return null

  return (
    <div className="modal-overlay" onClick={onClose}>
      <div className="modal settings-modal" ref={focusTrapRef as React.RefObject<HTMLDivElement>} onClick={(e) => e.stopPropagation()}>
        <div className="modal-header">
          <h2>Settings</h2>
          <button className="modal-close" onClick={onClose}>×</button>
        </div>
        <div className="modal-content">
          <VersionSettings
            appVersion={appVersion}
            updateStatus={updateStatus}
            onDownloadUpdate={onDownloadUpdate}
            onInstallUpdate={onInstallUpdate}
          />

          <ThemeSettings
            selectedTheme={general.selectedTheme}
            customization={general.themeCustomization}
            onThemeChange={onThemeChange}
            onSelect={(themeId) => setGeneral(prev => ({ ...prev, selectedTheme: themeId }))}
            onCustomizationChange={(customization) => setGeneral(prev => ({ ...prev, themeCustomization: customization }))}
          />

          <ProjectDirectorySettings
            defaultProjectDir={general.defaultProjectDir}
            onChange={(dir) => setGeneral(prev => ({ ...prev, defaultProjectDir: dir }))}
          />

          <PermissionsSettings
            autoAcceptTools={general.autoAcceptTools}
            permissionMode={general.permissionMode}
            customTool={general.customTool}
            onToggleTool={toggleTool}
            onPermissionModeChange={(mode) => setGeneral(prev => ({ ...prev, permissionMode: mode }))}
            onCustomToolChange={(tool) => setGeneral(prev => ({ ...prev, customTool: tool }))}
            onAddCustomTool={addCustomTool}
            onRemoveCustomTool={removeCustomTool}
          />

          <BackendSettings
            backend={general.backend}
            onChange={(backend) => setGeneral(prev => ({ ...prev, backend }))}
          />

          <ExtensionsSettings installedExtensions={installedExtensions} />

          <VoiceInputSettings
            whisperStatus={voice.whisperStatus}
            activeWhisperModel={activeWhisperModel}
            installingModel={ui.installingModel}
            onSetActiveModel={setActiveWhisperModel}
            onInstallModel={handleInstallWhisperModel}
          />

          <VoiceOutputSettings
            voice={voice}
            xtts={xtts}
            playingPreview={ui.playingPreview}
            previewLoading={ui.previewLoading}
            voiceVolume={voiceVolume}
            onVoiceSelect={handleVoiceSelect}
            onSpeedChange={(speed) => setVoice(prev => ({ ...prev, ttsSpeed: speed }))}
            onXttsChange={setXtts}
            onShowVoiceBrowser={() => setUI(prev => ({ ...prev, showVoiceBrowser: true }))}
            onPreviewStateChange={(state) => setUI(prev => ({ ...prev, ...state }))}
          />

          <UninstallTTSSection
            removingTTS={ui.removingTTS}
            ttsRemovalResult={ui.ttsRemovalResult}
            onRemove={handleRemoveTTSFromAllProjects}
          />
        </div>
        <div className="modal-footer">
          <a
            href="https://ko-fi.com/donutsdelivery"
            target="_blank"
            rel="noopener noreferrer"
            className="kofi-link"
            onClick={(e) => {
              e.preventDefault()
              window.electronAPI?.openExternal?.('https://ko-fi.com/donutsdelivery')
            }}
          >
            ♥ Support on Ko-fi
          </a>
          <div className="modal-footer-buttons">
            <button className="btn-secondary" onClick={onClose}>Cancel</button>
            <button className="btn-primary" onClick={handleSave}>Save</button>
          </div>
        </div>
      </div>

      <VoiceBrowserModal
        isOpen={ui.showVoiceBrowser}
        onClose={() => {
          setUI(prev => ({ ...prev, showVoiceBrowser: false }))
          refreshInstalledVoices()
        }}
        onVoiceSelect={(voiceKey, engine) => {
          setVoice(prev => ({
            ...prev,
            selectedVoice: voiceKey,
            selectedEngine: engine === 'xtts' ? 'xtts' : 'piper'
          }))
          window.electronAPI?.voiceSetVoice?.({ voice: voiceKey, engine })
        }}
      />
    </div>
  )
}

